import { globSync, readdirSync } from 'node:fs';
import { join, sep } from 'node:path';
function normalizePath(filePath) {
    return filePath.split(sep).join('/');
}
function expandFilePatterns(patterns) {
    const files = [];
    for (const pattern of patterns) {
        files.push(...globSync(pattern));
    }
    return files;
}
export function discoverExplicitFiles(patterns) {
    const files = expandFilePatterns(patterns);
    const flatListPatterns = patterns.length === 1 ? patterns[0].split(/\s+/).filter(Boolean) : [];
    return files.length > 0 || flatListPatterns.length <= 1
        ? files
        : expandFilePatterns(flatListPatterns);
}
export function discoverFilesByExtension(baseDir, extensions, useDotMatch) {
    const files = [];
    function walk(directory) {
        const entries = readdirSync(directory, { withFileTypes: true });
        for (const entry of entries) {
            if (!useDotMatch && entry.name.startsWith('.')) {
                continue;
            }
            const fullPath = join(directory, entry.name);
            if (entry.isDirectory()) {
                walk(fullPath);
                continue;
            }
            if (entry.isFile() &&
                extensions.some(extension => fullPath.endsWith(extension))) {
                files.push(normalizePath(fullPath));
            }
        }
    }
    walk(baseDir);
    return files;
}
